query GetWorkspace($id: String!) {
  workspace(id: $id) {
    id
    name
    adminCount
    memberCount
    invitations {
      id
      email
      createdTime
      __typename
    }
    defaultThemeId
    logoUrl
    workspaceMemberPermission
    accessLinkPermission
    gammaDataProcessingRole
    __typename
  }
}
